PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE settings (
    key TEXT PRIMARY KEY,
    value TEXT
  );
CREATE TABLE mat_raw (
    id TEXT PRIMARY KEY,
    code TEXT,
    name TEXT,
    spec TEXT,
    new_code TEXT,
    new_name TEXT,
    status TEXT DEFAULT '未治理',
    source TEXT,
    created_at INTEGER
  );
CREATE TABLE mat_archive (
    id TEXT PRIMARY KEY,
    code TEXT UNIQUE,
    name TEXT,
    synonyms TEXT,
    category TEXT,
    raw_count INTEGER DEFAULT 0,
    created_at INTEGER
  , vector_text TEXT);
CREATE TABLE categories (
    id TEXT PRIMARY KEY,
    code TEXT,
    l1 TEXT, l2 TEXT, l3 TEXT, l4 TEXT,
    status TEXT DEFAULT '正常',
    created_at INTEGER
  , key_attrs TEXT DEFAULT '', vector_text TEXT);
CREATE TABLE goods_raw (
    id TEXT PRIMARY KEY,
    code TEXT,
    name TEXT,
    std_code TEXT,
    std_name TEXT,
    status TEXT DEFAULT '未归一',
    source TEXT,
    created_at INTEGER
  , orig_code TEXT, orig_name TEXT, spec TEXT, brand TEXT, model TEXT, core_word TEXT, category_code TEXT, category_name TEXT, missing_attrs TEXT, std_name_proposed TEXT, match_status TEXT, orig_spec TEXT, attrs_json TEXT, review_candidates TEXT, review_reason TEXT, review_score TEXT, attr_pairs TEXT, attrs_vector TEXT, category_candidates TEXT, same_items TEXT, similar_items TEXT, same_count TEXT, similar_count TEXT, orig_brand TEXT);
CREATE TABLE goods_std (
    id TEXT PRIMARY KEY,
    code TEXT UNIQUE,
    name TEXT,
    category TEXT,
    attrs TEXT,
    raw_count INTEGER DEFAULT 0,
    mat_code TEXT,
    created_at INTEGER
  , category_code TEXT, attrs_vector TEXT, mat_candidates TEXT);
CREATE TABLE mapping (
    id TEXT PRIMARY KEY,
    goods_code TEXT,
    goods_name TEXT,
    mat_code TEXT,
    mat_name TEXT,
    type TEXT,
    method TEXT,
    created_at INTEGER
  );
CREATE TABLE mat_gov_tasks (
    id TEXT PRIMARY KEY,
    filename TEXT,
    total_rows INTEGER,
    success_count INTEGER,
    fail_count INTEGER,
    new_arch_count INTEGER,
    results_json TEXT,
    created_at INTEGER
  );
CREATE TABLE brands (
    id TEXT PRIMARY KEY,
    name TEXT UNIQUE,
    created_at INTEGER
  , code TEXT, logo_urls TEXT DEFAULT '');
CREATE UNIQUE INDEX idx_mat_raw_code ON mat_raw(code);
CREATE UNIQUE INDEX idx_brands_code_unique ON brands(code) WHERE code IS NOT NULL AND code <> '';
COMMIT;
